try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    let decision;
    try {
      const text = item.json.content[0].text;
      decision = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      decision = match ? JSON.parse(match[0]) : {action:'keep', reasoning:'Unable to parse', recommended_budget: 0};
    }
    results.push({json: {
      campaign_id: $node['Split In Batches'].json['id'],
      campaign_name: $node['Split In Batches'].json['campaign_name'],
      email: $node['Split In Batches'].json['business_email'] || '',
      action: decision.action || 'keep',
      reasoning: decision.reasoning || '',
      recommended_budget: decision.recommended_budget || 0,
      roas: $node['Split In Batches'].json['roas'] || 0
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
